const { app, BrowserWindow } = require('electron');
const path = require('path');
const { spawn } = require('child_process');
const http = require('http');
const fs = require('fs');

let mainWindow;
let apiProcess;
let webProcess;

// 判断是否为打包后的应用
const isDev = !app.isPackaged;

// 获取资源路径
function getResourcePath(relativePath) {
  if (isDev) {
    return path.join(__dirname, '..', relativePath);
  } else {
    // 打包后资源在 resources 目录
    return path.join(process.resourcesPath, relativePath);
  }
}

function checkServer(url, callback, timeout = 30000) {
  const startTime = Date.now();
  const checkInterval = setInterval(() => {
    if (Date.now() - startTime > timeout) {
      clearInterval(checkInterval);
      console.error(`Timeout waiting for ${url}`);
      callback(new Error('Timeout'));
      return;
    }

    http.get(url, (res) => {
      if (res.statusCode === 200) {
        clearInterval(checkInterval);
        callback(null);
      }
    }).on('error', () => {
      // 继续等待
    });
  }, 1000);
}

function startAPI() {
  const pythonPath = 'python';
  const apiDir = getResourcePath('api');

  console.log('Starting API from:', apiDir);
  console.log('API directory exists:', fs.existsSync(apiDir));

  if (!fs.existsSync(apiDir)) {
    console.error('API directory not found:', apiDir);
    return;
  }

  apiProcess = spawn(pythonPath, ['-m', 'uvicorn', 'app.main:app', '--host', '127.0.0.1', '--port', '8000'], {
    cwd: apiDir,
    shell: true,
    env: { ...process.env, PYTHONUNBUFFERED: '1' }
  });

  apiProcess.stdout.on('data', (data) => {
    console.log(`API: ${data}`);
  });

  apiProcess.stderr.on('data', (data) => {
    console.error(`API: ${data}`);
  });

  apiProcess.on('error', (err) => {
    console.error('Failed to start API:', err);
  });
}

function startWeb() {
  const webDir = getResourcePath('web');

  console.log('Starting Web from:', webDir);
  console.log('Web directory exists:', fs.existsSync(webDir));
  console.log('.next exists:', fs.existsSync(path.join(webDir, '.next')));

  if (!fs.existsSync(webDir)) {
    console.error('Web directory not found:', webDir);
    return;
  }

  // 生产模式使用 next start
  webProcess = spawn('npx', ['next', 'start', '-p', '3000'], {
    cwd: webDir,
    shell: true,
    env: { ...process.env, NODE_ENV: 'production' }
  });

  webProcess.stdout.on('data', (data) => {
    console.log(`Web: ${data}`);
  });

  webProcess.stderr.on('data', (data) => {
    console.error(`Web: ${data}`);
  });

  webProcess.on('error', (err) => {
    console.error('Failed to start Web:', err);
  });
}

