function findAvailablePort(startPort, callback) {
  const net = require('net');
  const server = net.createServer();

  server.listen(startPort, '127.0.0.1', () => {
    const port = server.address().port;
    server.close(() => {
      callback(port);
    });
  });

  server.on('error', () => {
    findAvailablePort(startPort + 1, callback);
  });
}

function startAPI() {
  const pythonPath = 'python';
  const apiDir = getResourcePath('api');

  console.log('Starting API from:', apiDir);
  console.log('API directory exists:', fs.existsSync(apiDir));

  if (!fs.existsSync(apiDir)) {
    console.error('API directory not found:', apiDir);
    return;
  }

  // 查找可用端口
  findAvailablePort(8000, (port) => {
    console.log(`Using API port: ${port}`);

    apiProcess = spawn(pythonPath, ['-m', 'uvicorn', 'app.main:app', '--host', '127.0.0.1', '--port', port.toString()], {
      cwd: apiDir,
      shell: true,
      env: { ...process.env, PYTHONUNBUFFERED: '1' }
    });

    apiProcess.stdout.on('data', (data) => {
      console.log(`API: ${data}`);
    });

    apiProcess.stderr.on('data', (data) => {
      console.error(`API: ${data}`);
    });

    apiProcess.on('error', (err) => {
      console.error('Failed to start API:', err);
    });
  });
}

