const { app, BrowserWindow } = require('electron');
const path = require('path');
const { spawn } = require('child_process');
const http = require('http');
const fs = require('fs');

let mainWindow;
let apiProcess;
let webProcess;

// 判断是否为打包后的应用
const isDev = !app.isPackaged;

// 获取资源路径
function getResourcePath(relativePath) {
  if (isDev) {
    return path.join(__dirname, '..', relativePath);
  } else {
    // 打包后资源在 resources 目录
    return path.join(process.resourcesPath, relativePath);
  }
}

function checkServer(url, callback, timeout = 30000) {
  const startTime = Date.now();
  const checkInterval = setInterval(() => {
    if (Date.now() - startTime > timeout) {
      clearInterval(checkInterval);
      console.error(`Timeout waiting for ${url}`);
      callback(new Error('Timeout'));
      return;
    }

    http.get(url, (res) => {
      if (res.statusCode === 200) {
        clearInterval(checkInterval);
        callback(null);
      }
    }).on('error', () => {
      // 继续等待
    });
  }, 1000);
}

function findAvailablePort(startPort, callback) {
  const net = require('net');
  const server = net.createServer();

  server.listen(startPort, '127.0.0.1', () => {
    const port = server.address().port;
    server.close(() => {
      callback(port);
    });
  });

  server.on('error', () => {
    findAvailablePort(startPort + 1, callback);
  });
}

function killProcessOnPort(port, callback) {
  const { exec } = require('child_process');

  // Windows 命令查找并杀死占用端口的进程
  exec(`netstat -ano | findstr :${port}`, (err, stdout) => {
    if (err || !stdout) {
      callback();
      return;
    }

    const lines = stdout.split('\n');
    const pids = new Set();

    lines.forEach(line => {
      const match = line.match(/LISTENING\s+(\d+)/);
      if (match) {
        pids.add(match[1]);
      }
    });

    if (pids.size === 0) {
      callback();
      return;
    }

    let killed = 0;
    pids.forEach(pid => {
      exec(`taskkill /F /PID ${pid}`, () => {
        killed++;
        if (killed === pids.size) {
          setTimeout(callback, 1000); // 等待端口释放
        }
      });
    });
  });
}

function startAPI() {
  const pythonPath = 'python';
  const apiDir = getResourcePath('api');
  const apiPort = 8000;

  console.log('Starting API from:', apiDir);
  console.log('API directory exists:', fs.existsSync(apiDir));

  if (!fs.existsSync(apiDir)) {
    console.error('API directory not found:', apiDir);
    return;
  }

  // 先清理端口
  killProcessOnPort(apiPort, () => {
    console.log(`Starting API on port ${apiPort}...`);

    apiProcess = spawn(pythonPath, ['-m', 'uvicorn', 'app.main:app', '--host', '127.0.0.1', '--port', apiPort.toString()], {
      cwd: apiDir,
      shell: true,
      env: { ...process.env, PYTHONUNBUFFERED: '1' }
    });

    apiProcess.stdout.on('data', (data) => {
      console.log(`API: ${data}`);
    });

    apiProcess.stderr.on('data', (data) => {
      console.error(`API: ${data}`);
    });

    apiProcess.on('error', (err) => {
      console.error('Failed to start API:', err);
    });
  });
}

function startWeb() {
  const webDir = getResourcePath('web');

  console.log('Starting Web from:', webDir);
  console.log('Web directory exists:', fs.existsSync(webDir));
  console.log('.next exists:', fs.existsSync(path.join(webDir, '.next')));

  if (!fs.existsSync(webDir)) {
    console.error('Web directory not found:', webDir);
    return;
  }

  // 查找可用端口
  findAvailablePort(3000, (port) => {
    console.log(`Using Web port: ${port}`);

    // 生产模式使用 next start
    webProcess = spawn('npx', ['next', 'start', '-p', port.toString()], {
      cwd: webDir,
      shell: true,
      env: { ...process.env, NODE_ENV: 'production' }
    });

    webProcess.stdout.on('data', (data) => {
      console.log(`Web: ${data}`);
    });

    webProcess.stderr.on('data', (data) => {
      console.error(`Web: ${data}`);
    });

    webProcess.on('error', (err) => {
      console.error('Failed to start Web:', err);
    });

    // 等待 Web 服务启动后加载
    setTimeout(() => {
      checkServer(`http://localhost:${port}`, (err) => {
        if (err) {
          console.error('Failed to start web server');
          mainWindow.loadURL('data:text/html,<html><body style="margin:0;padding:0;display:flex;align-items:center;justify-content:center;height:100vh;font-family:sans-serif;background:#f5f5f5"><div style="text-align:center"><h1 style="color:#e74c3c">启动失败</h1><p>Web 服务器启动超时</p><p style="color:#666;font-size:14px">请检查:</p><ul style="text-align:left;color:#666;font-size:14px"><li>Node.js 是否已安装</li><li>端口 3000 是否被占用</li><li>查看控制台日志 (F12)</li></ul></div></body></html>');
        } else {
          console.log('Web server is ready!');
          mainWindow.loadURL(`http://localhost:${port}`);
        }
      });
    }, 2000);
  });
}

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 1400,
    height: 900,
    show: false, // 先不显示
    webPreferences: {
      preload: path.join(__dirname, 'preload.js'),
